        .fub_axi_rready(xbar_apb_periph_axi_rready),

        // External side (m_axi)
        .m_axi_arid(apb_periph_mon_axi_arid),
        .m_axi_araddr(apb_periph_mon_axi_araddr),
        .m_axi_arlen(apb_periph_mon_axi_arlen),
        .m_axi_arsize(apb_periph_mon_axi_arsize),
        .m_axi_arburst(apb_periph_mon_axi_arburst),
        .m_axi_arlock(apb_periph_mon_axi_arlock),
        .m_axi_arcache(apb_periph_mon_axi_arcache),
        .m_axi_arprot(apb_periph_mon_axi_arprot),
        .m_axi_arqos(apb_periph_mon_axi_arqos),
        .m_axi_arregion(apb_periph_mon_axi_arregion),
        .m_axi_aruser(apb_periph_mon_axi_aruser),
        .m_axi_arvalid(apb_periph_mon_axi_arvalid),
        .m_axi_arready(apb_periph_mon_axi_arready),
