        .cfg_compl_enable(cfg_rd_compl_enable),
        .cfg_threshold_enable(cfg_rd_threshold_enable),
        .cfg_debug_enable(cfg_rd_debug_enable),
        .cfg_timeout_cycles(cfg_rd_timeout_cycles),
        .cfg_latency_threshold(cfg_rd_latency_threshold),
        .cfg_axi_pkt_mask(cfg_rd_axi_pkt_mask),
        .cfg_axi_err_select(cfg_rd_axi_err_select),
        .cfg_axi_error_mask(cfg_rd_axi_error_mask),
        .cfg_axi_timeout_mask(cfg_rd_axi_timeout_mask),
        .cfg_axi_compl_mask(cfg_rd_axi_compl_mask),
        .cfg_axi_thresh_mask(cfg_rd_axi_thresh_mask),
        .cfg_axi_perf_mask(cfg_rd_axi_perf_mask),
        .cfg_axi_addr_mask(cfg_rd_axi_addr_mask),
        .cfg_axi_debug_mask(cfg_rd_axi_debug_mask),

        // Address-range checker (disabled at N_ADDR_RANGES=0)
        .cfg_addr_check_enable(1'b0),
        .cfg_addr_range_enable(1'b0),
        .cfg_addr_range_low({32{1'b0}}),
        .cfg_addr_range_high({32{1'b0}}),

        // Perfmon Stage A/B (tied off -- no window driven)
        .cfg_start_event_sel(3'b111),
        .cfg_end_event_sel(3'b111),
        .cfg_start_trigger(1'b0),
        .cfg_end_trigger(1'b0),
        .cfg_window_force_close(1'b0),
        .window_active(),
        .window_cycles(),
        .perf_prod_cycles(),
        .perf_bp_cycles(),
        .perf_starv_cycles(),
        .perf_idle_cycles(),
        .perf_beat_count(),
        .perf_byte_count(),
        .perf_burst_count()
    );

    // AXI4-to-APB converter shim
    axi4_to_apb_shim #(
        .DEPTH_AW(2),
        .DEPTH_W(4),
        .DEPTH_B(2),
        .DEPTH_AR(2),
        .DEPTH_R(4),
        .SIDE_DEPTH(4),
        .APB_CMD_DEPTH(4),
        .APB_RSP_DEPTH(4),
        .AXI_ID_WIDTH(4),
        .AXI_ADDR_WIDTH(32),
        .AXI_DATA_WIDTH(32),
        .AXI_USER_WIDTH(1),
        .APB_ADDR_WIDTH(32),
        .APB_DATA_WIDTH(32)
    ) u_apb_periph_apb_converter (
        // Clocks and resets (single clock domain by default)
        .aclk(aclk),
        .aresetn(aresetn),
        .pclk(aclk),
        .presetn(aresetn),

        // AXI4 write channels (from crossbar)
        .s_axi_awid(apb_periph_mon_axi_awid),
        .s_axi_awaddr(apb_periph_mon_axi_awaddr),
        .s_axi_awlen(apb_periph_mon_axi_awlen),
        .s_axi_awsize(apb_periph_mon_axi_awsize),
        .s_axi_awburst(apb_periph_mon_axi_awburst),
        .s_axi_awlock(apb_periph_mon_axi_awlock),
        .s_axi_awcache(apb_periph_mon_axi_awcache),
        .s_axi_awprot(apb_periph_mon_axi_awprot),
        .s_axi_awqos(apb_periph_mon_axi_awqos),
        .s_axi_awregion(apb_periph_mon_axi_awregion),
        .s_axi_awuser(apb_periph_mon_axi_awuser),
        .s_axi_awvalid(apb_periph_mon_axi_awvalid),
        .s_axi_awready(apb_periph_mon_axi_awready),
        .s_axi_wdata(apb_periph_mon_axi_wdata),
        .s_axi_wstrb(apb_periph_mon_axi_wstrb),
        .s_axi_wlast(apb_periph_mon_axi_wlast),
        .s_axi_wuser(apb_periph_mon_axi_wuser),
        .s_axi_wvalid(apb_periph_mon_axi_wvalid),
        .s_axi_wready(apb_periph_mon_axi_wready),
        .s_axi_bid(apb_periph_mon_axi_bid),
        .s_axi_bresp(apb_periph_mon_axi_bresp),
        .s_axi_buser(apb_periph_mon_axi_buser),
        .s_axi_bvalid(converter_bvalid),
        .s_axi_bready(converter_bready),

        // AXI4 read channels (from crossbar)
        .s_axi_arid(apb_periph_mon_axi_arid),
        .s_axi_araddr(apb_periph_mon_axi_araddr),
        .s_axi_arlen(apb_periph_mon_axi_arlen),
        .s_axi_arsize(apb_periph_mon_axi_arsize),
        .s_axi_arburst(apb_periph_mon_axi_arburst),
        .s_axi_arlock(apb_periph_mon_axi_arlock),
        .s_axi_arcache(apb_periph_mon_axi_arcache),
        .s_axi_arprot(apb_periph_mon_axi_arprot),
        .s_axi_arqos(apb_periph_mon_axi_arqos),
        .s_axi_arregion(apb_periph_mon_axi_arregion),
        .s_axi_aruser(apb_periph_mon_axi_aruser),
        .s_axi_arvalid(apb_periph_mon_axi_arvalid),
        .s_axi_arready(apb_periph_mon_axi_arready),
        .s_axi_rid(apb_periph_mon_axi_rid),
        .s_axi_rdata(apb_periph_mon_axi_rdata),
        .s_axi_rresp(apb_periph_mon_axi_rresp),
        .s_axi_rlast(converter_rlast),
        .s_axi_ruser(apb_periph_mon_axi_ruser),
        .s_axi_rvalid(converter_rvalid),
        .s_axi_rready(converter_rready),

        // APB master interface (to external slave)
        .m_apb_PSEL(apb_periph_PSEL),
        .m_apb_PADDR(apb_periph_PADDR),
        .m_apb_PENABLE(apb_periph_PENABLE),
        .m_apb_PWRITE(apb_periph_PWRITE),
        .m_apb_PWDATA(apb_periph_PWDATA),
        .m_apb_PSTRB(apb_periph_PSTRB),
        .m_apb_PPROT(apb_periph_PPROT),
        .m_apb_PRDATA(apb_periph_PRDATA),
        .m_apb_PSLVERR(apb_periph_PSLVERR),
        .m_apb_PREADY(apb_periph_PREADY)
    );

    // Wire converter outputs back to shim's crossbar-facing interface
    assign apb_periph_mon_axi_bvalid = converter_bvalid;
    assign converter_bready = apb_periph_mon_axi_bready;
    assign apb_periph_mon_axi_rvalid = converter_rvalid;
    assign converter_rready = apb_periph_mon_axi_rready;
    assign apb_periph_mon_axi_rlast = converter_rlast;

endmodule : apb_periph_adapter
